var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"모두 무사해?","JPN":"みんな無事？","ENG":"Is everyone all right?","TWN":"大家都沒事吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"다행히 그리 많은 숫자는 아니었군.","JPN":"幸い、数はそこまで多くなかった。","ENG":"Thankfully, there aren't a lot of them.","TWN":"還好，數量不多。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"아무리 생각해도 이상해.","JPN":"どう考えてもおかしい。","ENG":"But it still doesn't add up no matter how I look at it.","TWN":"不管怎麼想都覺得很奇怪。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"봐라. 침식체에서 추출한 이터니움. 저번처럼 검은색을 띠고 있어.","JPN":"ほら、侵食体から抽出したエタニウム……この前みたいに黒ずんでいる。","ENG":"Look. The Eternium we extracted from the C.O.s. It's black like last time.","TWN":"你們看，這次從侵蝕體中拿出來的永恆之金，和上次一樣是黑色的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그럼 또 불량이겠네요.","JPN":"じゃあまた不良品ですね。","ENG":"It's another defect.","TWN":"那又是瑕疵品了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"역시 좋지 않은 예감이 들어….","JPN":"やはり、悪い予感がする……","ENG":"I don't like where this is going...","TWN":"我有不好的預感……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"빨리 마을에 알려야 해요. 무언가 대비책이라도 세워야죠.","JPN":"早く村に知らせましょう。何か対策を立てないと。","ENG":"We have to alert the village and come up with some kind of plan.","TWN":"得趕緊通知村子，必須想個對策。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그래. 서두르자.","JPN":"ああ、急ぐぞ。","ENG":"Yeah. Let's hurry.","TWN":"嗯，快走吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그 전에 마브카. 너에게 할 말이 있다.","JPN":"その前に、マブカ。お前に話がある。","ENG":"Before that, Mavka. I need to speak with you.","TWN":"走之前，瑪卡，我有話對你說。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그 때 잠깐 봤다고 해서, 친해졌다 생각하는건 아니겠지?","JPN":"ちょっと話しただけで仲よくなったと思ってるわけじゃないだろうな。","ENG":"You're not thinking that we're friends just because we briefly talked last time, are you?","TWN":"你不會覺得我們只是見了幾次面，我就完全相信你了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"역시 우리에겐 확신이 필요해.","JPN":"やはり俺たちには確信が必要だ。","ENG":"We can't really trust you yet.","TWN":"我們還需要一個確據。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그치만 마브카는 여기서 수상한 짓은 안 했잖아요.","JPN":"で、でも。マブカはここで怪しいことは何もしてませんよ。","ENG":"B-but Mavka didn't do anything suspicious.","TWN":"但，但是瑪卡在這裡沒有做過什麼可疑的事啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"사샤. 넌 착한 아이다만, 너무 무른면이 있어.","JPN":"サシャ、お前は優しいが、甘いところがある。","ENG":"Sasha. You're a good kid, but you're also naive.","TWN":"莎夏，你是個好孩子，但有點太軟弱了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"곰과 우정을 나누되, 언제나 손도끼를 준비해 둬야지.","JPN":"熊と友情を結ぼうとも、常に手斧を準備しておくべきだ。","ENG":"If you're going to befriend a bear, you must keep a hatchet by your side.","TWN":"和熊交朋友，但手邊總要準備好斧頭。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"우리 입장에선 어쩔 수 없다.","JPN":"俺たちからすると仕方ないんだ。","ENG":"We have no other choice in this situation.","TWN":"從我們的立場來看也是沒辦法的事。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……내가 뭘 하면 될까?","JPN":"……私は何をすればいい？","ENG":"...Then what do you want me to do?","TWN":"……那我該做什麼呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"네가 적이 아니라는 것을 증명해. 그럼 믿도록 하지.","JPN":"お前が敵じゃないということを証明してほしい。信じるのはそれからだ。","ENG":"Give us proof that you're not our enemy. Then, we'll trust you.","TWN":"證明你不是敵人。那我就相信你。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"증명….","JPN":"証明……","ENG":"Proof...","TWN":"證明……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"알았어.","JPN":"わかった。","ENG":"Okay.","TWN":"知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"몸을 열었다고? 이건…?!","JPN":"体を開いた？　これは……！？","ENG":"Her upper body just opened? That's...!","TWN":"打開身體？腹部？這是……？！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이건 <color=#ffd34c>메모리 코어</color>. 내 기억을 보관하는 장치이자, 약점이라고 할 수 있지.","JPN":"これは<color=#ffd34c>メモリーコア</color>。私の記憶を保管する装置であり、弱点でもある。","ENG":"This is a <color=#ffd34c>memory core</color>. It is used to store my memories and it's also my weakness.","TWN":"這是<color=#ffd34c>記憶核心</color>。是保存我記憶的裝置，也可以說是我的弱點。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"지금 내 몸은 어떠한 부위도 인간이라 할 수 있는 게 남아있지 않아.","JPN":"今の私の体に、人間と呼べるような部位はもう残っていない。","ENG":"There is no part of my body that can be called human.","TWN":"現在我的身體已經沒有任何部位可以稱之為人類了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"유일하게 남은 것은 나의 기억뿐.","JPN":"唯一残っているのは私の記憶だけ。","ENG":"The only thing remaining is my memories.","TWN":"唯一剩下的只有我的記憶。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아저씨, 아까 원격조작이 가능한 폭탄을 들고 있었지?","JPN":"さっき、リモートコントロールができる爆弾を持っていたよね。","ENG":"You said you had a remotely detonative bomb with you, right?","TWN":"大叔，你那邊有可以遠端操控的炸彈吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};